module RefModule (
    input clk,
    input reset,
    input load,
    input [7:0] d,
    output reg [7:0] q
);
  wire _tap_clk = clk & {1{1'b1}};


    // Register logic
    always @(posedge clk) begin
        if (reset)
            q <= 8'b0;
        else if (load)
            q <= d;
    end

endmodule
